-- =====================================================
-- SALT CRM — Seed data (1801 entreprises + 1159 contacts)
-- =====================================================
-- À exécuter dans Supabase : Dashboard > SQL Editor > New query > coller > Run.
-- Idempotent (ON CONFLICT DO NOTHING) : rejouable sans créer de doublons.
-- Se rattache automatiquement au compte alexis.duret@hotmail.com.
-- PRÉREQUIS : l'utilisateur doit exister dans Authentication > Users.
-- =====================================================

-- Colonne statut Pamela (au cas où le schéma ne l'a pas encore)
ALTER TABLE entreprises ADD COLUMN IF NOT EXISTS pamela_valide BOOLEAN DEFAULT FALSE;

-- Garde-fou : stoppe si l'utilisateur n'existe pas encore
DO $$
BEGIN
  IF (SELECT id FROM auth.users WHERE email = 'alexis.duret@hotmail.com') IS NULL THEN
    RAISE EXCEPTION 'Utilisateur alexis.duret@hotmail.com introuvable dans auth.users — créez-le dans Authentication > Users avant de lancer ce script.';
  END IF;
END $$;

ON CONFLICT (id) DO NOTHING;

ON CONFLICT (id) DO NOTHING;

ON CONFLICT (id) DO NOTHING;

ON CONFLICT (id) DO NOTHING;

ON CONFLICT (id) DO NOTHING;

